import React, { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { SessionContext } from '../context/SessionContext';
import { STAGE_CONFIG, WORKFLOW_STAGES } from '../workflow/stages';
import { SolverInputCard } from '../components/job/SolverInputCard';
import StatusIndicator from '../components/common/StatusIndicator';
import LoadingSpinner from '../components/common/LoadingSpinner';

const LogViewer = ({ logs }) => (
    <div className="bg-gray-900 text-white font-mono text-sm rounded-lg shadow-lg p-6 h-96 overflow-y-auto mt-6">
        {!logs || logs.length === 0 ? (
            <p className="text-gray-400">Awaiting execution logs...</p>
        ) : (
            logs.map((log, index) => (
                <div key={index} className="flex items-start">
                    <span className="text-gray-500 mr-4">{log.timestamp?.seconds ? new Date(log.timestamp.seconds * 1000).toLocaleTimeString() : '--:--:--'}</span>
                    <p className="flex-1">{log.message}</p>
                </div>
            ))
        )}
    </div>
);

function Execution() {
    const navigate = useNavigate();
    const { session, artifacts, loading, error, currentStageConfig } = useContext(SessionContext);

    // The main loading logic is now handled by the context.
    if (loading && !artifacts.execution) {
        return <LoadingSpinner text="Initializing execution environment..." />;
    }

    if (error) {
        return <div className="container mx-auto p-8 text-center text-red-500">{`Error: ${error.message}`}</div>;
    }

    // If the workflow has moved on, redirect.
    if (session?.currentStage === WORKFLOW_STAGES.REVIEW_RESULTS) {
        const resultsPath = STAGE_CONFIG[WORKFLOW_STAGES.REVIEW_RESULTS].path;
        navigate(`${resultsPath}?session=${session.id}`);
        return <LoadingSpinner text="Execution complete. Redirecting to results..." />;
    }

    // If we are in the execution stage but there's no execution artifact yet.
    if (session?.currentStage === WORKFLOW_STAGES.EXECUTE && !artifacts.execution) {
        return <LoadingSpinner text="Execution is starting..." />;
    }

    if (!session || !artifacts.solverInput) {
        return <div className="container mx-auto p-8 text-center">Job configuration not found. Please return to a previous step.</div>;
    }

    const { solverInput, execution } = artifacts;

    return (
        <div className="container mx-auto p-8">
            <div className="max-w-4xl mx-auto">
                <h1 className="text-4xl font-bold mb-4">Execution Monitor</h1>
                <p className="text-lg text-gray-600 mb-8">{currentStageConfig?.description}</p>

                <SolverInputCard contract={solverInput} isReadOnly={true} />

                <div className="mt-8 text-center">
                    <h3 className="text-xl font-semibold mb-2">Execution Status</h3>
                    <StatusIndicator status={execution?.status || 'pending'} />
                </div>

                <LogViewer logs={execution?.logs} />

            </div>
        </div>
    );
}

export default Execution;
